def main():
    base = Path(__file__).parent.parent
    data_path = base / "data" / "perfumes.json"
    json_path = base / "data" / "perfumes_to_add.json"
    
    with open(data_path, "r", encoding="utf-8") as f:
        perfumes = json.load(f)
    
    # perfumes_to_add.json varsa ekle
    all_extra = list(EXTRA_PERFUMES)
    if json_path.exists():
        with open(json_path, "r", encoding="utf-8") as f:
            from_json = json.load(f)
        for p in from_json:
            if "gender" not in p:
                p["gender"] = "unisex"
            all_extra.append(p)
    
    existing = {(p["brand"].lower(), p["name"].lower()) for p in perfumes}
    added = 0
    start_id = len(perfumes) + 1
    
    for p in all_extra:
        key = (p["brand"].lower(), p["name"].lower())
        if key not in existing:
            p = p.copy()
            p["id"] = str(start_id)
            perfumes.append(p)
            existing.add(key)
            start_id += 1
            added += 1
    
    with open(data_path, "w", encoding="utf-8") as f:
        json.dump(perfumes, f, indent=2, ensure_ascii=False)
    
    print(f"OK - Veritabani: {len(perfumes)} parfum (yeni eklenen: {added})")

if __name__ == "__main__":
    main()
